def multiply(a, b):
    return a * b

def square(n):
    return multiply(n, n)

def sum_of_squares(x, y):
    return square(x) + square(y)

print(sum_of_squares(3, 4))  # 25

# Порядок выполнения:
# 1. sum_of_squares(3, 4) запускается
# 2. square(3) → multiply(3, 3) → 9
# 3. square(4) → multiply(4, 4) → 16
# 4. sum_of_squares возвращает 9 + 16 = 25

# Рекурсия — функция вызывает сама себя
def factorial(n):
    if n == 0:
        return 1
    return n * factorial(n - 1)

print(factorial(5))  # 120  (5*4*3*2*1)

